  ('heelevel3-6f0ba476-moex-00403', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲有一宗A地，為二重買賣，先與乙訂立買賣契約，並將A地交付於乙；後與丙訂立買賣契約， 並將A地之所有權移轉登記於丙。關於甲、乙、丙三人間之法律關係，下列敘述，何者正確？', '["丙得請求乙返還A地之占有", "甲得請求乙返還A地之占有", "乙得請求丙移轉A地所有權", "甲得請求丙返還A地所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00404', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲、乙二人向丙、丁二人承租基地建築二層樓A屋，甲、乙分別共有A屋，丙、丁分別共有A屋 座落之基地。下列共有物，何者並非因物之使用目的而不能分割？', '["A屋座落之基地", "A屋之太平梯", "A屋之亭子腳", "A屋之共有車道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00405', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列何者，非為不動產物權依法律行為而得喪變更時之要件？', '["物權變動之合意", "書面", "交付", "登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00406', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列關於解除權與撤銷權之敘述，何者正確？', '["二者均屬形成權", "二者均適用於一切法律行為", "前者限於法律所規定；後者則包含約定與法定", "原則上二者均不溯及既往"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00407', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲之女乙嫁於丙為妻，甲與丙之父丁在法律上係何種關係？', '["姻親關係", "旁系血親關係", "直系血親關係", "無任何關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00408', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲乙為適用法定財產制之配偶。甲為減少乙將來對於剩餘財產之分配，而於 2018 年將時價新臺 幣（下同）2000 萬元婚後財產 A 屋，贈與並移轉 A 屋所有權於知情之丙。甲乙於 2022 年離婚 時，甲有婚後財產時價800萬元，乙有婚後財產時價1100萬元，丙所有之A屋價值2200萬元。 下列敘述，何者正確？', '["甲乙雙方婚後剩餘財產差額為300萬元", "甲得向乙請求分配150萬元", "甲乙雙方婚後剩餘財產差額為1900萬元", "乙得向丙請求返還50萬元 32620、33320"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00409', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲未婚產下乙，產後缺少照護而病故。乙成人後查明充分證據，乙係甲自丙受胎所生。乙找到丙 要求其應負責，丙因配偶丁在場而噤聲不語。下列敘述，何者正確？', '["因乙對丙之要求，已發生請求認領之效力，故乙為丙之準婚生子女", "如丙於遺囑中表示認領乙，因乙不知，故不生認領效力", "乙於丙死後，得向丙之繼承人丁提起認領之訴", "乙於丙死後向丁提起認領之訴，乙自勝訴判決確定日起，方為丙之繼承人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00410', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '遺囑未指定遺囑執行人，並未委託他人指定者，得由何人選定之？', '["遺囑管理人", "親屬會議", "繼承人", "檢察官"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00411', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列何種行為，雖經法定代理人允許，限制行為能力人亦不得為之？', '["加入漁會成為會員", "在票據上簽名", "擔任合會之會首", "加入職業工會成為會員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
